results.candidate_sql:
SELECT MAX("Percent (%) Eligible Free (K-12)") AS HighestEligibleFreeRate
FROM frpm
WHERE "County Name" = 'Alameda';

SELECT "School Code" 
FROM frpm 
WHERE ("Enrollment (K-12)" + "Enrollment (Ages 5-17)") > 500;

SELECT COUNT(*) 
FROM frpm 
WHERE "County Name" = 'Amador' AND "Low Grade" = 9 AND "High Grade" = 12;

SELECT Phone, Ext, School 
FROM schools 
WHERE Zip = '95203-3704';

SELECT Website 
FROM schools 
WHERE County = 'San Joaquin' AND Charter = 1 AND Virtual = 'P';

SELECT COUNT(*) 
FROM schools 
WHERE City = 'Hickman' AND Charter = 1 AND DOC = 52;

SELECT COUNT(*) 
FROM schools 
WHERE MailCity = 'Hickman' AND CharterNum = '00D4';

SELECT COUNT(*) AS Active_District_Community_Day_Schools
FROM schools
WHERE County = 'Alpine' AND StatusType IN ('Active', 'Closed') AND School LIKE '%District Community Day School%';

SELECT AdmLName1 AS AdministratorLastName, District, County, School 
FROM schools 
WHERE CharterNum = '40';

SELECT (COUNT(CASE WHEN status = 'C' THEN 1 END) * 100.0 / COUNT(*)) AS percentage_running_ok
FROM loan
WHERE amount < 100000;

SELECT A2 AS district_name, "A8" AS branch_location
FROM district
ORDER BY A13 DESC;

SELECT EXTRACT(YEAR FROM birth_date) AS birth_year 
FROM client 
WHERE client_id = 130;

SELECT COUNT(*) 
FROM molecule 
WHERE molecule_id BETWEEN 'TR000' AND 'TR099' AND label = '+';

SELECT CAST(SUM(CASE WHEN bond_type = '=' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(bond_id) AS percentage 
FROM bond 
WHERE molecule_id = 'TR008';

SELECT CAST(COUNT(CASE WHEN element = 'h' THEN 1 END) AS REAL) * 100 / COUNT(atom_id) AS hydrogen_percentage
FROM atom
WHERE molecule_id = 'TR206';

SELECT COUNT(*) 
FROM atom 
WHERE element IN ('C', 'H');

SELECT CAST(SUM(CASE WHEN bond_type = ' = ' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(bond_id) AS percent
FROM bond
WHERE molecule_id = 'TR047';

SELECT CASE WHEN label = '+' THEN 'Yes' ELSE 'No' END AS is_carcinogenic
FROM molecule
WHERE molecule_id = 'TR151';

SELECT CASE WHEN label = '+' THEN 'Yes' ELSE 'No' END AS is_carcinogenic
FROM molecule
WHERE molecule_id = 'TR124';

SELECT (SUM(CASE WHEN m.label = '+' AND a.element = 'h' THEN 1 ELSE 0 END) * 100.0 / COUNT(DISTINCT m.molecule_id)) AS percentage
FROM molecule m
JOIN atom a ON m.molecule_id = a.molecule_id;

SELECT CASE WHEN label = '+' THEN 'Carcinogenic' ELSE 'Non-Carcinogenic' END AS classification
FROM molecule
WHERE molecule_id = 'TR000';

SELECT (SUM(CASE WHEN b.bond_type = '-' THEN 1 ELSE 0 END) * 1.0 / COUNT(DISTINCT c.atom_id)) AS percentage
FROM connected c
JOIN bond b ON c.bond_id = b.bond_id;

SELECT DISTINCT language 
FROM foreign_data 
WHERE uuid IN (SELECT uuid FROM cards WHERE name = 'Annul' AND number = '29');

SELECT (COUNT(CASE WHEN T2.language = 'Chinese Simplified' THEN 1 ELSE NULL END) * 100.0 / COUNT(T1.id)) AS percentage
FROM cards AS T1
JOIN foreign_data AS T2 ON T1.uuid = T2.uuid;

SELECT COUNT(*) 
FROM cards 
WHERE originalType = 'Summon - Angel' AND (subtypes IS NULL OR subtypes != 'Angel');

SELECT COUNT(*) 
FROM cards 
WHERE artist = 'John Avon' AND (cardKingdomFoilId IS NULL OR cardKingdomId IS NULL);

SELECT manaCost 
FROM cards 
WHERE layout = 'normal' AND frameVersion = '2003' AND borderColor = 'black' AND availability = 'mtgo,paper';

SELECT DISTINCT subtypes, supertypes 
FROM cards 
WHERE availability = 'arena';

SELECT (COUNT(CASE WHEN isOnlineOnly = 1 THEN id ELSE NULL END) * 100.0 / COUNT(id)) AS percentage
FROM cards
WHERE frameEffects = 'legendary';

SELECT COUNT(*) 
FROM cards 
WHERE (power IS NULL OR power = '*') AND text LIKE '%triggered ability%';

SELECT COUNT(*) 
FROM cards 
WHERE borderColor = 'borderless' AND edhrecRank > 12000;

SELECT COUNT(*) 
FROM cards 
WHERE isOversized = 1 AND isReprint = 1 AND isPromo = 1;

SELECT number 
FROM cards 
WHERE side IS NULL AND subtypes LIKE '%Angel%' AND subtypes LIKE '%Wizard%';

SELECT COUNT(*) 
FROM cards 
WHERE availability LIKE '%paper%' AND hand = '3';

SELECT DISTINCT supertypes, subtypes 
FROM cards 
WHERE name = 'Molimo, Maro-Sorcerer';

SELECT COUNT(DISTINCT artist) 
FROM cards 
WHERE borderColor = 'black' AND availability LIKE '%arena,mtgo%';

SELECT COUNT(*) 
FROM users 
WHERE UpVotes > 100 AND DownVotes > 1;

SELECT SUM(CommentCount) 
FROM posts 
WHERE OwnerDisplayName = 'csgillespie';

SELECT MAX(AnswerCount) 
FROM posts 
WHERE OwnerUserId = (SELECT Id FROM users WHERE DisplayName = 'csgillespie');

SELECT COUNT(DISTINCT UserId) 
FROM badges 
WHERE Name = 'Supporter' AND strftime('%Y', Date) = '2011';

SELECT DISTINCT PostHistoryTypeId, COUNT(DISTINCT UserId) AS UniqueUserCount
FROM postHistory
WHERE PostId = 3720;

SELECT SUM(FavoriteCount)
FROM posts
WHERE OwnerUserId = 686 AND strftime('%Y', CreaionDate) = '2011';

SELECT CAST(COUNT(DISTINCT CASE WHEN b.Name = 'Teacher' THEN b.UserId ELSE NULL END) AS REAL) * 100 / COUNT(DISTINCT u.Id) AS TeacherBadgePercentage
FROM badges b
JOIN users u ON b.UserId = u.Id;

SELECT COUNT(DISTINCT UserId)
FROM badges
WHERE Name = 'Commentator' AND STRFTIME('%Y', Date) = '2014';

SELECT COUNT(*) 
FROM posts 
WHERE CreationDate BETWEEN '2010-07-21 00:00:00' AND '2010-07-21 23:59:59';

SELECT COUNT(*) 
FROM posts 
WHERE ViewCount > (SELECT AVG(ViewCount) FROM posts);

SELECT COUNT(*) 
FROM posts 
WHERE ViewCount > 35000 AND CommentCount = 0;

SELECT COUNT(*) 
FROM users 
WHERE Age BETWEEN 19 AND 65 AND UpVotes > 5000;

SELECT COUNT(DISTINCT PostId) 
FROM votes 
WHERE BountyAmount >= 30;

SELECT COUNT(*)
FROM tags
WHERE Id < 15 AND Count <= 20;

SELECT 
    (SELECT weight_kg FROM superhero WHERE full_name = 'Emil Blonsky') -
    (SELECT weight_kg FROM superhero WHERE full_name = 'Charles Chandler') AS weight_difference;

SELECT COUNT(*) 
FROM superhero 
WHERE race_id = 21 AND gender_id = 1;

SELECT (SUM(CASE WHEN c.colour = 'Blue' THEN 1 ELSE 0 END) * 100.0 / COUNT(s.superhero_name)) AS percentage_blue_eyes
FROM superhero s
JOIN colour c ON s.eye_colour_id = c.id;

SELECT name 
FROM races 
WHERE date = (SELECT MIN(date) FROM races);

SELECT count(*), name, lat, lng 
FROM circuits 
WHERE country = 'Austria';

SELECT SUM(wins) AS total_victories
FROM driverStandings
WHERE position = 91;

SELECT AVG(height) AS average_height 
FROM Player 
WHERE birthday >= '1990-01-01' AND birthday < '1996-01-01';

SELECT player_name 
FROM Player 
WHERE SUBSTR(birthday, 1, 4) = '1970' AND SUBSTR(birthday, 6, 2) = '10';

SELECT Player.player_name, Player_Attributes.potential
FROM Player
JOIN Player_Attributes ON Player.player_api_id = Player_Attributes.player_api_id
WHERE Player_Attributes.potential = (
    SELECT MAX(potential) FROM Player_Attributes
);

SELECT COUNT(*) 
FROM Player 
WHERE player_name LIKE 'Adam%' AND weight > 170;

SELECT COUNT(*) 
FROM Player_Attributes 
WHERE preferred_foot = 'left' AND attacking_work_rate = 'low';

SELECT CAST(SUM(CASE WHEN P.height < 180 AND PA.overall_rating > 70 THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) 
FROM Player P 
JOIN Player_Attributes PA ON P.player_api_id = PA.player_api_id;

SELECT CAST(SUM(CASE WHEN Birthday > '1930-12-31' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(ID) AS Percentage 
FROM Patient 
WHERE SEX = 'F';

SELECT CAST(SUM(CASE WHEN Admission = '+' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) 
FROM Patient 
WHERE strftime('%Y', Birthday) BETWEEN '1930' AND '1940';

SELECT CAST(SUM(CASE WHEN P.SEX = 'F' AND (L.TP < 6.0 OR L.TP > 8.5) THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(P.ID) 
FROM Patient P 
JOIN Laboratory L ON P.ID = L.ID;

SELECT Symptoms, Diagnosis 
FROM Examination 
WHERE ID = (SELECT ID FROM Patient ORDER BY Birthday DESC LIMIT 1) AND Symptoms IS NOT NULL;

SELECT CASE WHEN T_CHO < 250 THEN 'Normal' ELSE 'Not Normal' END AS Cholesterol_Status 
FROM Laboratory 
WHERE ID = 2927464 AND Date = '1995-09-04';

SELECT CAST(SUM(CASE WHEN UA <= 6.5 THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) 
FROM Laboratory 
WHERE `U-PRO` > 0 AND `U-PRO` < 30;

SELECT CAST(SUM(CASE WHEN Diagnosis = 'BEHCET' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) 
FROM Patient 
WHERE SEX = 'M' AND STRFTIME('%Y', `First Date`) = '1981';

SELECT COUNT(ID) 
FROM Laboratory 
WHERE YEAR(Date) = 1997 AND (TP <= 6 OR TP >= 8.5);

SELECT (SUM(CASE WHEN Symptoms = 'thrombocytopenia' THEN 1 ELSE 0 END) / SUM(CASE WHEN Diagnosis = 'SLE' THEN 1 ELSE 0 END)) * 100 AS Proportion
FROM Patient
WHERE Diagnosis = 'SLE' OR Symptoms = 'thrombocytopenia';

SELECT CAST(SUM(CASE WHEN SEX = 'F' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) 
FROM Patient 
WHERE YEAR(Birthday) = 1980 AND Diagnosis = 'RA';

SELECT CAST(SUM(CASE WHEN T2.GOT >= 60 AND T1.Diagnosis = 'SLE' THEN 1 ELSE 0 END) AS REAL) * 100 / SUM(CASE WHEN T2.GOT >= 60 THEN 1 ELSE 0 END) AS Percentage
FROM Patient T1
JOIN Laboratory T2 ON T1.ID = T2.ID;

SELECT L.ANA 
FROM Laboratory L 
WHERE L.`T-BIL` = (SELECT MAX(L2.`T-BIL`) FROM Laboratory L2 WHERE L2.`T-BIL` < 2.0);

SELECT COUNT(DISTINCT city) 
FROM zip_code 
WHERE county = 'Orange County' AND state = 'Virginia';

SELECT COUNT(*) 
FROM event 
WHERE type = 'Meeting' AND strftime('%Y', event_date) = '2020';

SELECT (CAST(SUM(CASE WHEN type = 'Community Service' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(event_id)) AS percentage
FROM event
WHERE event_date BETWEEN '2019-01-01' AND '2019-12-31';

SELECT SUM(cost) AS total_expense 
FROM expense 
WHERE expense_date = '2019-08-20';

SELECT CAST(SUM(CASE WHEN T2.major_name = 'Business' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(T1.member_id) 
FROM member AS T1 
JOIN major AS T2 ON T1.link_to_major = T2.major_id;

SELECT COUNT(*) 
FROM major 
WHERE college = 'College of Agriculture and Applied Sciences' AND department = 'School of Applied Sciences, Technology and Education';

SELECT SUM(Consumption) AS Total_Consumption
FROM yearmonth
WHERE CustomerID = 6 AND Date BETWEEN '201308' AND '201311';

SELECT 
    (SELECT COUNT(*) FROM gasstations WHERE Country = 'CZE' AND Segment = 'discount') -
    (SELECT COUNT(*) FROM gasstations WHERE Country = 'SVK' AND Segment = 'discount') AS difference;

SELECT (COUNT(CASE WHEN Currency = 'Euro' THEN CustomerID ELSE NULL END) * 100.0 / COUNT(CustomerID)) AS PercentageOfKAMUsingEuro
FROM customers
WHERE Segment = 'KAM';

SELECT CAST(SUM(CASE WHEN Consumption > 528.3 THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) 
FROM yearmonth 
WHERE Date = '201202';

SELECT (SUM(CASE WHEN Segment = 'premium' THEN 1 ELSE 0 END) * 1.0 / COUNT(*)) * 100 AS PremiumPercentage
FROM gasstations
WHERE Country = 'Slovakia';

SELECT MAX(Consumption) AS HighestMonthlyConsumption
FROM yearmonth
WHERE Date LIKE '2012%';

SELECT AVG(Amount * Price) AS AverageTotalPrice
FROM transactions_1k
WHERE Date LIKE '2012-01%';

SELECT DISTINCT Time 
FROM transactions_1k 
WHERE GasStationID IN (SELECT GasStationID FROM gasstations WHERE ChainID = 11);

SELECT ProductID 
FROM transactions_1k 
WHERE Date = '2012-08-23' AND Time = '21:20:00';
